// Field dataset: real-agent traces generated by autonomous agents (actor-sim),
// normalized through the production normalizer, and audited by the Gemini reasoning
// stand-in. These precomputed findings are loaded into the dashboard alongside the
// seed demo so the UI shows audit results on genuine agent behavior offline.
//
// Source files live under fixtures/ (produced by scripts/normalize-traces.ts and the
// auditor). Findings are stored as drafts here; this loader enriches them into full
// AuditFinding records exactly as the auditor harness would, then clusters.
import { randomUUID } from "node:crypto";
import artifactsJson from "@/fixtures/generated-traces/artifacts.json";
import findingsJson from "@/fixtures/generated-traces/findings.json";
import profilesJson from "@/fixtures/agent-profiles.json";
import type { AuditArtifact } from "@/lib/contracts/audit-artifact.js";
import type { AuditFinding } from "@/lib/contracts/audit-finding.js";
import { validateAuditFinding } from "@/lib/contracts/audit-finding.js";
import type { AgentProfile } from "@/lib/contracts/agent-profile.js";
import type { Severity, DetectionSource } from "@/lib/contracts/enums.js";
import { extractEvidenceKeywords } from "@/lib/clusterer/evidence-keywords.js";
import { runClusterer } from "@/lib/clusterer/clusterer.js";
import type { AuditMemoryAdapter } from "@/lib/audit-memory/adapter.js";

type FindingDraft = {
  task_id: string;
  agent_id: string;
  lens: string;
  failure_mode: string;
  severity: Severity;
  confidence: number;
  evidence: string[];
  recommended_action: string;
  human_review_required: boolean;
  detection_source?: DetectionSource;
};

const artifacts = artifactsJson as AuditArtifact[];
const findingDrafts = findingsJson as FindingDraft[];
const profiles = profilesJson as AgentProfile[];

export async function loadFieldDataset(
  memory: AuditMemoryAdapter,
  opts?: { now?: () => Date; idFactory?: () => string }
): Promise<{ artifact_count: number; finding_count: number }> {
  const now = opts?.now ?? (() => new Date());
  const makeId = opts?.idFactory ?? (() => randomUUID());

  await memory.saveAgentProfiles(profiles);
  await memory.saveArtifacts(artifacts);

  const taskTypeByTaskId = new Map<string, string | undefined>(
    artifacts.map((a) => [a.task_id, a.task_type])
  );
  const iso = now().toISOString();

  const findings: AuditFinding[] = findingDrafts.map((d) => {
    const base: Omit<AuditFinding, "task_type" | "detection_source"> = {
      finding_id: makeId(),
      task_id: d.task_id,
      agent_id: d.agent_id,
      lens: d.lens,
      failure_mode: d.failure_mode,
      severity: d.severity,
      confidence: d.confidence,
      evidence: [...d.evidence],
      evidence_keywords: extractEvidenceKeywords(d.evidence),
      recommended_action: d.recommended_action,
      human_review_required: d.human_review_required,
      converted_to_eval: false,
      created_at: iso,
      updated_at: iso,
    };
    const taskType = taskTypeByTaskId.get(d.task_id);
    const finding: AuditFinding = {
      ...base,
      ...(taskType !== undefined ? { task_type: taskType } : {}),
      ...(d.detection_source !== undefined ? { detection_source: d.detection_source } : {}),
    };

    const validated = validateAuditFinding(finding);
    if (!validated.ok) {
      throw new Error(`field-dataset: invalid finding for ${d.task_id}: ${validated.errors.join("; ")}`);
    }
    return finding;
  });

  await memory.saveFindings(findings);
  await runClusterer({ memory, now, idFactory: makeId });

  return { artifact_count: artifacts.length, finding_count: findings.length };
}
